def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    es_config = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'retry_on_timeout': True,
        'max_retries': 3,
        'timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        es_config['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**es_config)


es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       in_stock=None, sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with relevance scoring and filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search with multi-match for relevance
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',           # Product name has highest weight
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1',
                    'tags^1',
                    'sku'
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%'
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # In-stock filter
    if in_stock is not None:
        filter_clauses.append({
            'term': {'in_stock': in_stock}
        })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses
        }
    }

    # Sort configuration
    sort = []
    if sort_by:
        valid_sort_fields = ['price', 'created_at', 'rating', 'popularity', 'name.keyword']
        if sort_by in valid_sort_fields:
            sort.append({sort_by: {'order': sort_order}})

    # Always add relevance score as secondary sort (or primary if no sort specified)
    sort.append('_score')

    return query, sort


def build_aggregations():
    """Build aggregations for faceted search."""
    return {
        'categories': {
            'terms': {
                'field': 'category.keyword',
                'size': 50
            }
        },
        'brands': {
            'terms': {
                'field': 'brand.keyword',
                'size': 50
            }
        },
        'price_ranges': {
            'range': {
                'field': 'price',
                'ranges': [
                    {'key': 'under_25', 'to': 25},
                    {'key': '25_to_50', 'from': 25, 'to': 50},
                    {'key': '50_to_100', 'from': 50, 'to': 100},
                    {'key': '100_to_200', 'from': 100, 'to': 200},
                    {'key': 'over_200', 'from': 200}
                ]
            }
        },
        'avg_price': {
            'avg': {
                'field': 'price'
            }
        },
        'in_stock_count': {
            'filter': {
                'term': {'in_stock': True}
            }
        }
    }


def format_search_results(es_response, page, page_size):
    """Format Elasticsearch response into API response."""
    hits = es_response.get('hits', {})
    total = hits.get('total', {})
    total_count = total.get('value', 0) if isinstance(total, dict) else total

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['score'] = hit.get('_score')

        # Include highlights if available
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']

        products.append(product)

    # Format aggregations
    facets = {}
    aggregations = es_response.get('aggregations', {})
    if aggregations:
        if 'categories' in aggregations:
            facets['categories'] = [
                {'name': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggregations['categories'].get('buckets', [])
            ]
        if 'brands' in aggregations:
            facets['brands'] = [
                {'name': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggregations['brands'].get('buckets', [])
            ]
        if 'price_ranges' in aggregations:
            facets['price_ranges'] = [
                {'range': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggregations['price_ranges'].get('buckets', [])
            ]
        if 'avg_price' in aggregations:
            facets['avg_price'] = aggregations['avg_price'].get('value')
        if 'in_stock_count' in aggregations:
            facets['in_stock_count'] = aggregations['in_stock_count'].get('doc_count', 0)

    total_pages = (total_count + page_size - 1) // page_size if page_size > 0 else 0

    return {
        'results': products,
        'pagination': {
            'total': total_count,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1
        },
        'facets': facets
    }


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.
    
    Query Parameters:
        q (str): Search keyword (required)
        page (int): Page number (default: 1)
        page_size (int): Results per page (default: 20, max: 100)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        in_stock (bool): Filter by stock availability
        sort_by (str): Sort field (price, created_at, rating, popularity, name.keyword)
        sort_order (str): Sort order (asc, desc; default: desc)
        include_facets (bool): Include aggregation facets (default: true)
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
            'status': 400
        }), 400

    if len(keyword) > 500:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" exceeds maximum length of 500 characters',
            'status': 400
        }), 400

    try:
        page = max(1, int(request.args.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(MAX_PAGE_SIZE, max(1, int(request.args.get('page_size', DEFAULT_PAGE_SIZE))))
    except (ValueError, TypeError):
        page_size = DEFAULT_PAGE_SIZE

    category = request.args.get('category', None)

    min_price = None
    max_price = None
    try:
        if request.args.get('min_price'):
            min_price = float(request.args.get('min_price'))
            if min_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'min_price must be non-negative',
                    'status': 400
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price must be a valid number',
            'status': 400
        }), 400

    try:
        if request.args.get('max_price'):
            max_price = float(request.args.get('max_price'))
            if max_price < 0:
                return jsonify({
                    'error': 'Invalid parameter',
                    'message': 'max_price must be non-negative',
                    'status': 400
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'max_price must be a valid number',
            'status': 400
        }), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'min_price cannot be greater than max_price',
            'status': 400
        }), 400

    in_stock = None
    in_stock_param = request.args.get('in_stock')
    if in_stock_param is not None:
        in_stock = in_stock_param.lower() in ('true', '1', 'yes')

    sort_by = request.args.get('sort_by', None)
    sort_order = request.args.get('sort_order', 'desc').lower()
    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    include_facets = request.args.get('include_facets', 'true').lower() in ('true', '1', 'yes')

    # Build the search query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        in_stock=in_stock,
        sort_by=sort_by,
        sort_order=sort_order
    )

    # Calculate offset
    from_offset = (page - 1) * page_size

    # Build the search body
    search_body = {
        'query': query,
        'sort': sort,
        'from': from_offset,
        'size': page_size,
        'timeout': SEARCH_TIMEOUT,
        'highlight': {
            'fields': {
                'name': {
                    'number_of_fragments': 1,
                    'fragment_size': 150
                },
                'description': {
                    'number_of_fragments': 2,
                    'fragment_size': 200
                }
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>']
        },
        '_source': {
            'includes': [
                'name', 'description', 'price', 'category', 'brand',
                'image_url', 'rating', 'review_count', 'in_stock',
                'sku', 'created_at', 'tags'
            ]
        },
        'track_total_hits': True
    }

    if include_facets:
        search_body['aggregations'] = build_aggregations()

    # Add suggest for typo correction
    search_body['suggest'] = {
        'text': keyword,
        'product_suggest': {
            'phrase': {
                'field': 'name',
                'size': 3,
                'gram_size': 3,
                'direct_generator': [{
                    'field': 'name',
                    'suggest_mode': 'popular'
                }],
                'highlight': {
                    'pre_tag': '<em>',
                    'post_tag': '</em>'
                }
            }
        }
    }

    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=10
        )
    except Exception as e:
        logger.error(f"Elasticsearch query failed: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'Unable to process search request. Please try again later.',
            'status': 503
        }), 503

    # Format the response
    response = format_search_results(es_response, page, page_size)

    # Add suggestions if available
    suggestions = []
    suggest_data = es_response.get('suggest', {}).get('product_suggest', [])
    for suggestion in suggest_data:
        for option in suggestion.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'highlighted': option.get('highlighted'),
                'score': option.get('score')
            })
    if suggestions:
        response['suggestions'] = suggestions

    # Add metadata
    elapsed_time = time.time() - start_time
    response['meta'] = {
        'query': keyword,
        'took_ms': es_response.get('took', 0),
        'api_took_ms': round(elapsed_time * 1000, 2),
        'timed_out': es_response.get('timed_out', False)
    }

    result = jsonify(response)
    # Add cache headers for CDN/reverse proxy caching during high traffic
    result.headers['Cache-Control'] = 'public, max-age=30, s-maxage=60'
    result.headers['Vary'] = 'Accept-Encoding'

    return result, 200


@app.route('/api/search/suggest', methods=['GET'])
def search_suggest():
    """
    Autocomplete/suggestion endpoint for search-as-you-type.
    
    Query Parameters:
        q (str): Partial search keyword
        size (int): Number of suggestions (default: 5, max: 20)
    """
    keyword = request.args.get('q', '').strip()
    if not keyword or len(keyword) < 2:
        return jsonify({'suggestions': []}), 200

    try:
        size = min(20, max(1, int(request.args.get('size', 5))))
    except (ValueError, TypeError):
        size = 5

    search_body = {
        'size': 0,
        'suggest': {
            'product_completion': {
                'prefix': keyword,
                'completion': {
                    'field': 'name.suggest',
                    'size': size,
                    'skip_duplicates': True,
                    'fuzzy': {
                        'fuzziness': 'AUTO'
                    }
                }
            }
        }
    }

    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=3
        )
    except Exception as e:
        logger.error(f"Suggestion query failed: {str(e)}")
        return jsonify({'suggestions': []}), 200

    suggestions = []
    suggest_data = es_response.get('suggest', {}).get('product_completion', [])
    for suggestion in suggest_data:
        for option in suggestion.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'id': option.get('_id'),
                'score': option.get('_score')
            })

    result = jsonify({'suggestions': suggestions})
    result.headers['Cache-Control'] = 'public, max-age=60, s-maxage=120'
    return result, 200


@app.route('/api/search/health', methods=['GET'])
def search_health():
    """Health check endpoint for load balancers and monitoring."""
    try:
        health = es_client.cluster.health(timeout='3s')
        es_status = health.get('status', 'unknown')
        is_healthy = es_status in ('green', 'yellow')

        return jsonify({
            'status': 'healthy' if is_healthy else 'unhealthy',
            'elasticsearch': {
                'status': es_status,
                'cluster_name': health.get('cluster_name'),
                'number_of_nodes': health.get('number_of_nodes'),
                'active_shards': health.get('active_shards')
            }
        }), 200 if is_healthy else 503
    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'error': str(e)
        }), 503


