# Index setup utility (for initial setup)
def create_product_index():
    """Create the products index with optimized mappings for search."""
    index_settings = {
        'settings': {
            'number_of_shards': 3,
            'number_of_replicas': 1,
            'refresh_interval': '1s',
            'analysis': {
                'analyzer': {
                    'autocomplete_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase', 'autocomplete_filter']
                    },
                    'search_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase']
                    }
                },
                'filter': {
                    'autocomplete_filter': {
                        'type': 'edge_ngram',
                        'min_gram': 2,
                        'max_gram': 20
                    }
                }
            }
        },
        'mappings': {
            'properties': {
                'name': {
                    'type': 'text',
                    'analyzer': 'standard',
                    'fields': {
                        'keyword': {'type': 'keyword'},
                        'autocomplete': {
                            'type': 'text',
                            'analyzer': 'autocomplete_analyzer',
                            'search_analyzer': 'search_analyzer'
                        },
                        'suggest': {
                            'type': 'completion'
                        }
                    }
                },
                'description': {
                    'type': 'text',
                    'analyzer': 'standard'
                },
                'price': {'type': 'float'},
                'category': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'brand': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'tags': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'sku': {'type': 'keyword'},
                'image_url': {'type': 'keyword', 'index': False},
                'rating': {'type': 'float'},
                'review_count': {'type': 'integer'},
                'in_stock': {'type': 'boolean'},
                'popularity': {'type': 'integer'},
                'created_at': {'type': 'date'}
            }
        }
    }

    if not es_client.indices.exists(index=ES_INDEX):
        es_client.indices.create(index=ES_INDEX, body=index_settings)
        logger.info(f"Created index '{ES_INDEX}' with mappings")
    else:
        logger.info(f"Index '{ES_INDEX}' already exists")


